"use strict";

window.BoxSprite = function () {

    function BoxSprite(size, lineWidth, z, color, opacity) {
        this.z = z || 0;
        this.mesh = null;
        this.size = { width: size.width + lineWidth, height: size.height + lineWidth };

        this.color = color;
        this.opacity = opacity;

        this.mesh = create.call(this, this.size, lineWidth);
    }

    BoxSprite.prototype = Object.create(webglSprite.prototype);

    function createSide(positions, indices, p1, p2, p3, p4, i) {
        positions.push(p1.x, p1.y, p1.z);
        positions.push(p2.x, p2.y, p2.z);
        positions.push(p3.x, p3.y, p3.z);
        positions.push(p4.x, p4.y, p4.z);

        var a = i * 4;

        indices.push(a + 2, a + 1, a);
        indices.push(a + 2, a + 3, a + 1);

        return ++i;
    }

    function create(size, lineWidth) {
        var width = size.width;
        var height = size.height;

        var geometry = new THREE.BufferGeometry();
        var positions = [];
        var indices = [];
        var i = 0;

        i = createSide(positions, indices, new THREE.Vector3(-width / 2, height / 2, 0), new THREE.Vector3(-width / 2 + lineWidth, height / 2, 0), new THREE.Vector3(-width / 2, -height / 2, 0), new THREE.Vector3(-width / 2 + lineWidth, -height / 2, 0), i);

        i = createSide(positions, indices, new THREE.Vector3(width / 2, -height / 2, 0), new THREE.Vector3(width / 2 - lineWidth, -height / 2, 0), new THREE.Vector3(width / 2, height / 2, 0), new THREE.Vector3(width / 2 - lineWidth, height / 2, 0), i);

        i = createSide(positions, indices, new THREE.Vector3(-width / 2, -height / 2, 0), new THREE.Vector3(-width / 2, -height / 2 + lineWidth, 0), new THREE.Vector3(width / 2, -height / 2, 0), new THREE.Vector3(width / 2, -height / 2 + lineWidth, 0), i);

        i = createSide(positions, indices, new THREE.Vector3(width / 2, height / 2, 0), new THREE.Vector3(width / 2, height / 2 - lineWidth, 0), new THREE.Vector3(-width / 2, height / 2, 0), new THREE.Vector3(-width / 2, height / 2 - lineWidth, 0), i);

        geometry.setAttribute('position', new THREE.BufferAttribute(new Float32Array(positions), 3));
        geometry.setIndex(indices);
        geometry.computeBoundingSphere();

        this.material = new THREE.MeshBasicMaterial({ color: this.color, transparent: true, opacity: this.opacity });

        var mesh = new THREE.Mesh(geometry, this.material);

        mesh.position.z = this.z;
        return mesh;
    }

    return BoxSprite;
}();;

/* Source: client/renderer/sprite/PlainSprite.js */
"use strict";

window.PlainSprite = function () {

    function PlainSprite(size, z, color, opacity, avail) {
        this.z = z || 0;
        this.size = size;

        // Create the colored plane mesh exactly as before
        this.mesh = createPlane.call(this, size, color, opacity);

        // If avail is provided, create and add a text sprite on top
        if (typeof avail === 'number' && avail > 1) {
            this.addTextSprite(avail);
        }
    }

    PlainSprite.prototype = Object.create(webglSprite.prototype);

    function createPlane(size, color, opacity) {
        var mesh = new THREE.Mesh(
            new THREE.PlaneGeometry(size.width, size.height, 1, 1),
            new THREE.MeshBasicMaterial({ color: color, transparent: true, opacity: opacity })
        );
        mesh.position.z = this.z;
        return mesh;
    }

PlainSprite.prototype.addTextSprite = function(avail) {
    var canvas = document.createElement('canvas');
    canvas.width = 256;
    canvas.height = 128;
    var ctx = canvas.getContext('2d');

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = 'white';
    ctx.font = 'bold 48px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText("Turn " + avail, canvas.width / 2, canvas.height / 2);

    var texture = new THREE.CanvasTexture(canvas);
        texture.colorSpace = THREE.SRGBColorSpace;
    texture.minFilter = THREE.LinearFilter;
    texture.magFilter = THREE.LinearFilter;
    texture.needsUpdate = true;

    var material = new THREE.SpriteMaterial({
        map: texture,
        transparent: true,
        opacity: 0.15,
        depthTest: false,
        depthWrite: false
    });

    var sprite = new THREE.Sprite(material);

    const zoneAspect = this.size.width / this.size.height;
    const textAspect = canvas.width / canvas.height; // 2

    const maxWidth = this.size.width * 0.8;
    const maxHeight = this.size.height * 0.8;

    let scaleX, scaleY;
    if (zoneAspect > textAspect) {
      // Limit by height
      scaleY = maxHeight;
      scaleX = scaleY * textAspect;
    } else {
      // Limit by width
      scaleX = maxWidth;
      scaleY = scaleX / textAspect;
    }

    sprite.scale.set(scaleX, scaleY, 1);
    sprite.position.set(0, 0, this.z - 0.01);

    this.mesh.add(sprite);
};

    return PlainSprite;
}();;

