/* Source: client/renderer/animationStrategy/animation/LogAnimation.js */
"use strict";

window.LogAnimation = function () {

    function LogAnimation() {
        Animation.call(this);
        this.entries = [];
        this.nextToDisplay = null;
        this.nextToHide = null;
        this.currentTime = 0;
    }

    LogAnimation.prototype = Object.create(Animation.prototype);

    LogAnimation.prototype.render = function (now, total, last, delta) {

        var lastCurrentTime = this.currentTime;
        this.currentTime = total;

        if (lastCurrentTime > total) {
            //moving backwards in time
            tryToHideNext.call(this);
        } else {
            tryToShowNext.call(this);
        }
    };

    LogAnimation.prototype.addLogEntryFire = function (fire, time) {
        this.entries.push({ time: time, fire: fire, displayed: null });
        calculateDisplay.call(this);
    };

    LogAnimation.prototype.addLogEntryDestroyed = function (ship, time, jumped) {
        this.entries.push({ time: time, ship: ship, displayed: null, jumped : jumped });
        calculateDisplay.call(this);
    };

    LogAnimation.prototype.addLogEntryMove = function (movement, time) {
        this.entries.push({ time: time, movement: movement, displayed: null });
        calculateDisplay.call(this);
    };

    LogAnimation.prototype.cleanUp = function () {
        this.entries.forEach(function (entry) {
            if (entry.fire || entry.ship) {
                window.combatLog.removeFireOrders(entry.displayed);
            } else {
                //window.combatLog.removeMoves(entry.movement);
            }
        });
        window.combatLog.critsShown = {}; //Empty crits shown array
        window.combatLog.critAnimations = {}; //Empty crit animations shown array                         
    };

    function tryToHideNext() {
        if (this.nextToHide && this.currentTime < this.nextToHide.time) {
            if (this.nextToHide.fire) {
                window.combatLog.removeFireOrders(this.nextToHide.displayed);
            } else if (this.nextToHide.ship){
                window.combatLog.removeFireOrders(this.nextToHide.displayed);
            } else {
                //window.combatLog.removeMoves(this.nextToHide.movement);
            }

            calculateDisplay.call(this);
        }
    }

    function tryToShowNext() {
        if (this.nextToDisplay && this.currentTime > this.nextToDisplay.time) {
            if (this.nextToDisplay.fire) {
                this.nextToDisplay.displayed = window.combatLog.logFireOrders(this.nextToDisplay.fire);
            }  else if (this.nextToDisplay.ship){
                this.nextToDisplay.displayed = window.combatLog.logDestroyedShip(this.nextToDisplay.ship, this.nextToDisplay.jumped);
            }else {
                //window.combatLog.logMoves(this.nextToDisplay.movement);
            }

            calculateDisplay.call(this);
        }
    }

    function calculateDisplay() {

        var next = null;
        var nextTime = null;

        var last = null;
        var lastTime = null;

        this.entries.forEach(function (entry) {

            var timeDiff = entry.time - this.currentTime;

            if (timeDiff > 0) {
                if (nextTime === null || timeDiff < nextTime - this.currentTime) {
                    next = entry;
                    nextTime = entry.time;
                }
            } else {
                if (lastTime === null || timeDiff > lastTime - this.currentTime) {
                    last = entry;
                    lastTime = entry.time;
                }
            }
        }, this);

        this.nextToDisplay = next;
        this.nextToHide = last;
    }

    return LogAnimation;
}();;

/* Source: client/renderer/animationStrategy/animation/CameraPositionAnimation.js */
"use strict";

window.CameraPositionAnimation = function () {

    function CameraPositionAnimation(position, time, endTime) {
        Animation.call(this);
        this.time = time;
        this.position = position;
        this.lastTime = null;
        this.endTime = 0;

        this.duration = 1000;

        if (endTime === undefined) {
            this.endTime = 300;
        }

        this.startPosition = null;

        this.curve = new THREE.CubicBezierCurve(new THREE.Vector2(0, 0), new THREE.Vector2(0.5, 0.0), new THREE.Vector2(0.5, 1), new THREE.Vector2(1, 1));
    }

    CameraPositionAnimation.prototype = Object.create(Animation.prototype);

    CameraPositionAnimation.prototype.render = function (now, total, last, delta, zoom, back, paused) {
        smoothMove.call(this, now, total, last, delta, zoom, back);
    };

    function smoothMove(now, total, last, delta, zoom, back, paused) {
        if (back) {
            return;
        }

        if (total > this.time && total < this.time + this.duration && !paused) {
            if (this.startPosition === null) {
                this.startPosition = {
                    x: window.webglScene.camera.position.x,
                    y: window.webglScene.camera.position.y
                };
            }
            var done = 1 - (this.time + this.duration - total) / this.duration;
            var point = this.curve.getPoint(done).y;

            var position = mathlib.getPointBetween(this.startPosition, this.position, point, true);

            doMove(position);
        } else {
            this.startPosition = null;
        }
    }

    function instantMove(now, total, last, delta, zoom, back) {
        if (back) {
            return;
        }

        if (this.lastTime !== null && this.lastTime < this.time && total > this.time) {
            doMove(this.position);
        }

        this.lastTime = total;
    }

    CameraPositionAnimation.prototype.getDuration = function () {
        return this.duration + this.endTime;
    };

    function doMove(position) {
        window.webglScene.moveCameraTo(position);
    }

    return CameraPositionAnimation;
}();;

/* Source: client/renderer/animationStrategy/animation/ShipDestroyedAnimation.js */
"use strict";

window.ShipDestroyedAnimation = function () {
    function ShipDestroyedAnimation(time, shipIcon, emitterContainer, movementAnimations) {
        Animation.call(this);
        this.time = time;
        this.shipIcon = shipIcon;
        this.fadeoutTime = time + 2100;
        this.fadeoutDuration = 500;
        this.currentOpacity = 1.0;

        this.animations = [];
        this.explosionTriggered = false;
        this.soundTriggered = false;
        this.emitterContainer = emitterContainer;
        this.movementAnimations = movementAnimations;

        const cameraAnimation = new CameraPositionAnimation(
            FireAnimationHelper.getShipPositionAtTime(this.shipIcon, this.time, this.movementAnimations),
            this.time
        );

        this.animations.push(cameraAnimation);
        this.duration = 4000; // match explosion duration
    }

    ShipDestroyedAnimation.prototype = Object.create(Animation.prototype);

    ShipDestroyedAnimation.prototype.render = function (now, total, last, delta, zoom, back, paused) {
        this.animations.forEach(animation => animation.render(now, total, last, delta, zoom, back, paused));

        if (!this.explosionTriggered && total >= this.time) {
            this.explosionTriggered = true;

            const position = FireAnimationHelper.getShipPositionAtTime(this.shipIcon, this.time, this.movementAnimations);

            // --- Trigger explosion visuals ---
            this.explosion = new ShipExplosion(this.emitterContainer, {
                time: this.time,
                position: position
            });
        }

        // --- Trigger explosion sound (only if not paused or reversing) ---
        if (!this.soundTriggered && total >= this.time && gamedata.playAudio && !paused && !back) {
            this.soundTriggered = true;
            ShipDestroyedAnimation.playExplosionSound();
        }

        // --- Fadeout ---
        let opacity;
        if (total > this.fadeoutTime && total < this.fadeoutTime + this.fadeoutDuration) {
            opacity = 1 - (total - this.fadeoutTime) / this.fadeoutDuration;
        } else if (total < this.fadeoutTime) {
            opacity = 1;
        } else {
            opacity = 0;
        }

        if (this.currentOpacity !== opacity) {
            this.currentOpacity = opacity;
            this.shipIcon.setOpacity(opacity);
        }
    };

    ShipDestroyedAnimation.playExplosionSound = function () {
        if (!ShipDestroyedAnimation.cachedAudio) {
            ShipDestroyedAnimation.cachedAudio = new Audio("client/renderer/animationStrategy/animation/sound/ShipExplosionAudio.wav");
            ShipDestroyedAnimation.cachedAudio.volume = 0.1;
        }

        try {
            const explosionSound = ShipDestroyedAnimation.cachedAudio.cloneNode(true);
            explosionSound.currentTime = 0;
            explosionSound.play().catch(() => { });
        } catch (e) {
            console.warn("Explosion sound playback failed:", e);
        }
    };

    ShipDestroyedAnimation.prototype.getDuration = function () {
        return this.duration;
    };

    ShipDestroyedAnimation.prototype.cleanUp = function () {
        this.shipIcon.setOpacity(1);
    };

    return ShipDestroyedAnimation;
}();


