"use strict";

window.ReplayPhaseStrategy = function () {

    function ReplayPhaseStrategy(coordinateConverter) {
        PhaseStrategy.call(this, coordinateConverter);
        this.webglScene = null;
        this.currentTurn = null;
        this.currentPhase = null;
        this.replayTurn = null;
        this.replayPhase = null;
        this.allBallistics = null;  //New variable added so that ballisticLineIcons can be rendered during Replay - DK 12/24 

        this.loading = false;
    }

    ReplayPhaseStrategy.prototype = Object.create(window.PhaseStrategy.prototype);

    ReplayPhaseStrategy.prototype.activate = function (shipIcons, ewIconContainer, ballisticIconContainer, gamedata, webglScene, shipWindowManager) {
        this.shipIconContainer = shipIcons;
        this.ewIconContainer = ewIconContainer;
        this.ewIconContainer.hide();
        this.ballisticIconContainer = ballisticIconContainer;
        this.gamedata = gamedata;
        this.webglScene = webglScene;
        this.inactive = false;
        this.currentTurn = gamedata.turn;
        this.currentPhase = gamedata.gamephase;
        this.setSelectShip(null);
        this.shipIconContainer.setAllSelected(false);
        this.replayTurn = getInitialReplayTurn.call(this);

        this.shipIconContainer.consumeGamedata(this.gamedata);
        this.ewIconContainer.consumeGamedata(this.gamedata);
        this.shipWindowManager = shipWindowManager;
        gamedata.replay = true;
        this.createReplayUI();

        startReplayOrRequestGamedata.call(this);

        activatePause.call(this);

        this.setPhaseHeader(false);
        this.showAppropriateHighlight();
        this.showAppropriateEW();

        infowindow.informPhase(5000, function () { });
        var combatLogContainer = document.getElementById('combatLogContainer');
        if (combatLogContainer) combatLogContainer.style.display = 'none'; //Hide print Log buttons
        return this;
    };

    ReplayPhaseStrategy.prototype.deactivate = function () {
        PhaseStrategy.prototype.deactivate.call(this, true);
        gamedata.replay = false;
        var combatLogContainer = document.getElementById('combatLogContainer');
        if (combatLogContainer) combatLogContainer.style.display = 'block'; //Show print Log buttons
        return this;
    };

    ReplayPhaseStrategy.prototype.update = function (gamedata) {
        this.gamedata = gamedata;
        this.shipIconContainer.consumeGamedata(this.gamedata);
        this.ewIconContainer.consumeGamedata(this.gamedata, this.shipIconContainer);

        startReplayOrRequestGamedata.call(this);
    };

    ReplayPhaseStrategy.prototype.done = function () { };

    ReplayPhaseStrategy.prototype.onHexClicked = function (payload) {
        PhaseStrategy.prototype.onHexClicked.call(this, payload);
    };

    ReplayPhaseStrategy.prototype.selectShip = function (ship, payload) {
        var menu = new ShipTooltipMenu(this.selectedShip, ship, this.gamedata.turn);
        this.showShipTooltip(ship, payload, menu, false);
    };

    ReplayPhaseStrategy.prototype.setSelectShip = function (ship, payload) {
    };

    ReplayPhaseStrategy.prototype.targetShip = function (ship, payload) {
        var menu = new ShipTooltipMenu(this.selectedShip, ship, this.gamedata.turn);
        this.showShipTooltip(ship, payload, menu, false);
    };

    ReplayPhaseStrategy.prototype.onMouseOverShip = function (ship, payload) {
        if (this.animationStrategy.isPaused()) {
            PhaseStrategy.prototype.onMouseOverShip.call(this, ship, payload);
        }
    };

    ReplayPhaseStrategy.prototype.createReplayUI = function (gamedata) {
        this.replayUI = new ReplayUI(true, {
            play: activateButton.bind(this, "play"),
            pause: activateButton.bind(this, "pause"),
            back: activateButton.bind(this, "back"),
            turnForward: turnForward.bind(this),
            turnBack: turnBack.bind(this),
            endReplay: requestPlayableGamedata.bind(this),
            toMovementPhase: toMovementPhase.bind(this),
            toFiringPhase: toFiringPhase.bind(this)
        }).activate();
    };

    ReplayPhaseStrategy.prototype.render = function (coordinateConverter, scene, zoom) {
        PhaseStrategy.prototype.render.call(this, coordinateConverter, scene, zoom);

        if (this.animationStrategy && this.animationStrategy.isDone && this.animationStrategy.isDone()) {
            activatePause.call(this);
        }
    };

    ReplayPhaseStrategy.prototype.showAppropriateEW = function () {
        this.shipIconContainer.getArray().forEach(icon => {
            icon.hideEW();
            icon.hideBDEW();
        });

        this.ewIconContainer.hide();
        if (this.selectedShip) {
            this.showShipEW(this.selectedShip);
        }
    }

    ReplayPhaseStrategy.prototype.showAppropriateHighlight = function () {
        this.shipIconContainer.getArray().forEach(icon => {
            icon.showSideSprite(false);
            icon.setHighlighted(false);
        })
    }

    function toMovementPhase() {
        this.animationStrategy.toMovementPhase();
        this.replayUI.activateButton('#pause');
        resetAudio.call(this);
        window.combatLog.critsShown = {}; //Empty crits shown array
        window.combatLog.critAnimations = {}; //Empty crit animations shown array                          
        this.animationStrategy.pause();
    }

    function toFiringPhase() {
        this.animationStrategy.toFiringPhase();
        this.replayUI.activateButton('#pause');
        resetAudio.call(this);
        window.combatLog.critsShown = {}; //Empty crits shown array
        window.combatLog.critAnimations = {}; //Empty crit animations shown array                               
        this.animationStrategy.pause();
    }

    //To reset audio when player clicks on Movement or Firing buttons in Replay, otherwise the sound only plays once.
    function resetAudio(value = false) {
        for (const animContainer of this.animationStrategy.animations) {

            // --- 🏃 0. Skip pure movement animations (no audio at all) ---
            const isMovementAnimation =
                animContainer?.shipIcon &&
                animContainer?.turnCurve &&
                !animContainer?.emitters &&
                !animContainer?.particleEmitterContainer &&
                !animContainer?.movementAnimations;

            if (isMovementAnimation) continue;

            // --- 1. Handle emitter-based containers (Bolt/Missile/Torpedo) ---
            if (animContainer.emitters?.length) {
                const firstEmitter = animContainer.emitters[0];
                if (firstEmitter?.reservations?.length) {
                    for (const reservation of firstEmitter.reservations) {
                        const anim = reservation.animation;
                        if (
                            anim instanceof BoltEffect ||
                            anim instanceof MissileEffect ||
                            anim instanceof TorpedoEffect ||
                            anim instanceof BlinkEffect
                        ) {
                            anim.playedLaunchSound = value;
                            anim.playedImpactSound = value;
                        }
                    }
                }
                continue;
            }

            if (animContainer instanceof ShipDestroyedAnimation || animContainer instanceof ShipJumpAnimation) {
                animContainer.explosionTriggered = value;
                continue;
            }
            // --- 2. Handle AllWeaponFireAgainstShipAnimation containers ---
            const isAllWeaponFire =
                animContainer?.movementAnimations &&
                animContainer?.shipIconContainer &&
                animContainer?.particleEmitterContainer &&
                animContainer?.logAnimation &&
                !animContainer?.emitters;

            // --- 3. Handle ShipDestroyedAnimation containers ---
            /*const isShipDestruction =
                animContainer instanceof ShipDestroyedAnimation ||
                (
                    animContainer?.shipIcon &&
                    animContainer?.fadeoutTime &&
                    typeof animContainer?.explosionTriggered === "boolean" &&
                    !animContainer?.emitters
                );*/

            if (isAllWeaponFire) {
                for (const effect of animContainer.animations) {
                    if (effect instanceof LaserEffect) {
                        effect.playedSound = value;
                    }
                }
            }
        }
    }


    ReplayPhaseStrategy.prototype.onToggleSound = function (payload) {
        if (payload.up) return; // Prevent repeats

        const now = Date.now();

        if (gamedata.playAudio) {
            // 🔇 Turn sound OFF            
            gamedata.playAudio = false;
        } else {
            // 🔊 Turn sound ON            
            gamedata.playAudio = true;

        }

        window.dispatchEvent(new CustomEvent("soundToggled"));
    };

    function startReplayOrRequestGamedata() {
        if (this.replayTurn === this.gamedata.turn) {
            this.changeAnimationStrategy(new ReplayAnimationStrategy(this.gamedata, this.shipIconContainer, webglScene.scene));
            this.replayUI.setTurn(this.replayTurn);
        } else {
            if (!this.animationStrategy) {
                this.changeAnimationStrategy(new IdleAnimationStrategy(this.shipIconContainer, this.gamedata.turn));
                this.animationStrategy.update(this.gamedata);
            }

            requestReplayGamedata.call(this);
        }
    }

    function activateButton(action, event) {

        if (this.loading) {
            return;
        }

        this.replayUI.activateButton(event.target);

        this.animationStrategy[action]();
    }

    function activatePause() {
        this.replayUI.activateButton("#pause");
        this.animationStrategy.pause();
    }

    function getInitialReplayTurn() {

        if (this.currentTurn === 1 && this.currentPhase <= 1) {
            return 0;
        }

        if (this.currentPhase === 1) {
            return this.currentTurn - 1;
        }

        return this.currentTurn;
    }

    function turnBack() {
        if (this.replayTurn == 1 || this.loading) {
            return;
        }

        this.replayTurn--;
        activatePause.call(this);
        requestReplayGamedata.call(this);
    }

    function turnForward() {
        if (this.replayTurn === getInitialReplayTurn.call(this) || this.loading) {
            return;
        }

        this.replayTurn++;
        activatePause.call(this);
        requestReplayGamedata.call(this);
    }

    /*
    function requestReplayGamedata() {
        startLoading.call(this);

        jQuery.ajax({
            type: 'GET',
            url: 'replay.php',
            dataType: 'json',
            data: {
                turn: this.replayTurn,
                gameid: this.gamedata.gameid,
                time: new Date().getTime()
            },
            success: function (data) {
                gamedata.parseServerData(data); 
                //New section called at this point so that ballisticIcons can be rendered during Replay - DK 10/24  
                this.allBallistics = weaponManager.getAllFireOrdersForAllShipsForTurn(gamedata.turn, 'ballistic');		
                this.ballisticIconContainer.consumeGamedata(this.gamedata, this.shipIconContainer, this.allBallistics);         		
                stopLoading.call(this);
            }.bind(this),
            error: ajaxInterface.errorAjax
        });
    } 

    function requestPlayableGamedata() {
        startLoading.call(this);

        jQuery.ajax({
            type: 'GET',
            url: 'gamedata.php',
            dataType: 'json',
            data: {
                turn: -1,
                phase: 0,
                activeship: -1,
                gameid: gamedata.gameid,
                playerid: gamedata.thisplayer || -1,
                time: new Date().getTime(),
                force: true
            },
            success: function (data) {
                gamedata.replay = false;
                stopLoading.call(this);
                gamedata.parseServerData(data);
            }.bind(this),
            error: ajaxInterface.errorAjax
        });
    }    
    
*/
    //New versions to use ajaxWithRetry()
    function requestReplayGamedata() {
        startLoading.call(this);

        ajaxInterface.ajaxWithRetry({
            type: 'GET',
            url: 'replay.php',
            dataType: 'json',
            data: {
                turn: this.replayTurn,
                gameid: this.gamedata.gameid,
                time: new Date().getTime()
            },
            success: function (data) {
                gamedata.parseServerData(data);
                gamedata.replay = true;
                // New section so ballisticIcons render during Replay
                this.allBallistics = weaponManager.getAllFireOrdersForAllShipsForTurn(
                    gamedata.turn,
                    'ballistic'
                );

                this.ballisticIconContainer.consumeGamedata(
                    this.gamedata,
                    this.shipIconContainer,
                    this.allBallistics
                );
            }.bind(this),
            error: ajaxInterface.errorAjax,
            complete: function () {
                stopLoading.call(this);
            }.bind(this)
        });
    }

    function requestPlayableGamedata() {
        startLoading.call(this);

        ajaxInterface.ajaxWithRetry({
            type: 'GET',
            url: 'gamedata.php',
            dataType: 'json',
            data: {
                turn: -1,
                phase: 0,
                activeship: -1,
                gameid: gamedata.gameid,
                playerid: gamedata.thisplayer || -1,
                time: new Date().getTime(),
                force: true
            },
            success: function (data) {
                gamedata.replay = false;
                gamedata.parseServerData(data);
            }.bind(this),
            error: ajaxInterface.errorAjax,
            complete: function () {
                stopLoading.call(this);
            }.bind(this)
        });
    }


    function startLoading() {
        this.loading = true;
        this.replayUI.startLoading();
    }

    function stopLoading() {
        this.loading = false;
        this.replayUI.stopLoading();
    }

    return ReplayPhaseStrategy;
}();;

/* Source: client/renderer/terrain/StarField.js */
window.StarField = (function(){

    function StarField(webglScene)
    {
        this.starCount = 5000;
        this.emitterContainer = null;
        this.webglScene = webglScene;
        this.lastAnimationTime = null;
        this.totalAnimationTime = 0;
        this.zoomChanged = 0;

        this.getRandom = null;

        this.create();

    };

    StarField.prototype.create = function()
    {
        
        return;
        this.cleanUp();

        this.emitterContainer = new ParticleEmitterContainer(this.webglScene.scene, this.starCount, StarParticleEmitter);


        this.webglScene.scene.background = new THREE.Color(10/255, 10/255, 30/255);
        var width =  3000; //this.webglScene.width * 1.5; 
        var height = 2000; // this.webglScene.height * 1.5; 

        this.getRandom = mathlib.getSeededRandomGenerator(gamedata.gameid);

        //var stars = Math.floor(this.starCount * (width / 4000));
        var stars = this.starCount;
        while(stars--) {
            createStar.call(this, width, height);

            if (this.getRandom() > 0.98) {
                createShiningStar.call(this, width, height);
            }
        }

        var gas = Math.floor(this.getRandom() * 5) + 8; 
        
        while(gas--){
            createGasCloud.call(this, width, height)
        }

        this.emitterContainer.start();
        this.lastAnimationTime = new Date().getTime();
        this.totalAnimationTime = 0;
        this.zoomChanged = 1;
        return this;
    };

    StarField.prototype.cleanUp  = function() {
        if (this.emitterContainer) {
            this.emitterContainer.cleanUp();
            this.emitterContainer = null;
        }
    }   

    StarField.prototype.render = function()
    {

        
        return;
        if (! this.emitterContainer) {
            this.create();
        }

        
        var deltaTime = new Date().getTime() - this.lastAnimationTime;
        this.totalAnimationTime += deltaTime;
        this.emitterContainer.render(0, this.totalAnimationTime, 0, 0, this.zoomChanged);

        if (this.zoomChanged === 1) {
            this.zoomChanged = 0;
        }

        this.lastAnimationTime = new Date().getTime();
    };

    function createStar(width, height) {
        var particle = this.emitterContainer.getParticle(this);

        var x = ((this.getRandom() - 0.5) * width * 1.5);
        var y = ((this.getRandom() - 0.5) * height * 1.5);

        particle
            .setActivationTime(0)
            .setSize(2 + this.getRandom() * 2)
            .setOpacity(this.getRandom() * 0.2 + 0.9)
            .setPosition({x: x, y: y})
            .setColor(new THREE.Color(1, 1, 1))
            .setParallaxFactor(0.005 + this.getRandom() * 0.005);

        if (this.getRandom() > 0.9) {
            particle
                .setSineFrequency(this.getRandom() * 200 + 50)
                .setSineAmplitude(this.getRandom());
        }
            
    }

    function createShiningStar(width, height) {
        var particle = this.emitterContainer.getParticle(this);

        var x = ((this.getRandom() - 0.5) * width * 1.5);
        var y = ((this.getRandom() - 0.5) * height * 1.5);

        var size = 6 + this.getRandom() * 6;
        var parallaxFactor = 0.005 + this.getRandom() * 0.005;
        var color = new THREE.Color(this.getRandom() * 0.4 + 0.6, this.getRandom() * 0.2 + 0.8, this.getRandom() * 0.4 + 0.6);

        particle
            .setActivationTime(0)
            .setSize(size*0.5)
            .setOpacity(this.getRandom() * 0.2 + 0.9)
            .setPosition({x: x, y: y})
            .setColor(new THREE.Color(1,1,1))
            .setParallaxFactor(parallaxFactor);

        particle = this.emitterContainer.getParticle(this);
        particle
            .setActivationTime(0)
            .setSize(size)
            .setOpacity(this.getRandom() * 0.1 + 0.1)
            .setPosition({x: x, y: y})
            .setColor(color)
            .setParallaxFactor(parallaxFactor)
            .setSineFrequency(this.getRandom() * 200 + 100)
            .setSineAmplitude(this.getRandom() * 0.4);
            
        var shines = Math.round(this.getRandom() * 8) - 3;

        if (shines <= 2) {
            return
        }
        
        var angle = this.getRandom() * 360;
        var angleChange = (this.getRandom() - 0.5) * 0.01;

        while (shines--) {

            angle += this.getRandom() * 60 + 40   
            particle = this.emitterContainer.getParticle(this);
            particle
                .setActivationTime(0)
                .setSize(size * this.getRandom() * 10 + 10)
                .setOpacity(this.getRandom() * 0.1 + 0.1)
                .setPosition({x: x, y: y})
                .setColor(color)
                .setParallaxFactor(parallaxFactor)
                .setSineFrequency(this.getRandom() * 200 + 100)
                .setSineAmplitude(0.1)
                .setAngle(angle)
                .setAngleChange(angleChange)
                .setTexture(particle.texture.starLine);
        }
        
    }

    function createGasCloud(width, height) {
        var gas = Math.floor(this.getRandom() * 10 + 10);
    
        var position = {
            x: ((this.getRandom() - 0.5) * width),
            y: ((this.getRandom() - 0.5) * height)
        }

        var vector = {
            x: getRandomBand.call(this, 0.5, 1) * width / 100,
            y: getRandomBand.call(this, 0.5, 1) * width / 100
        }

        var iterations = Math.floor(this.getRandom() * 3) + 5;

        while(iterations--) {
            createGasCloudPart.call(this, {x: position.x, y: position.y}, width);
            position.x += getRandomBand.call(this, 0, 1) * 50 + vector.x; 
            position.y += getRandomBand.call(this, 0, 1) * 50 + vector.y; 
        }
    }

    function getRandomBand(min, max) {
        var random = this.getRandom() * (max-min) + min;
        return this.getRandom() > 0.5 ? random * -1 : random;
    }

    function createGasCloudPart(position, width) {
        var gas = Math.floor(this.getRandom() * 5 + 5);
        var baseRotation = (this.getRandom() - 0.5) * 0.002;

        while(gas--) {  
            createGas.call(this, position, baseRotation, this.getRandom() * width * 0.40  + width * 0.40)
        }
    }

    function createGas(position, baseRotation, size){
        var particle = this.emitterContainer.getParticle(this);

        position.x += (this.getRandom() - 0.5) * 100; 
        position.y += (this.getRandom() - 0.5) * 100;

        particle
            .setActivationTime(0)
            .setSize( this.getRandom() * size*0.5 + size*0.5)
            .setOpacity(this.getRandom() * 0.005 + 0.005)
            .setPosition({x: position.x, y: position.y})
            .setColor(new THREE.Color(104/255, 204/255, 249/255))
            .setTexture(particle.texture.gas)   
            .setAngle(this.getRandom() * 360)
            .setAngleChange(baseRotation + (this.getRandom() - 0.5) * 0.001)
            .setParallaxFactor(0.005 + this.getRandom() * 0.005);

        if (this.getRandom() > 0.9) {
            particle
                .setActivationTime(0)
                .setSize( this.getRandom() * size*0.25 + size*0.25)
                .setOpacity(0)
                .setPosition({x: position.x, y: position.y})
                .setColor(new THREE.Color(1, 1, 1))
                .setTexture(particle.texture.gas)   
                .setAngle(this.getRandom() * 360)
                .setAngleChange(baseRotation + (this.getRandom() - 0.5) * 0.01)
                .setParallaxFactor(0.005 + this.getRandom() * 0.005)
                .setSineFrequency(this.getRandom() * 200 + 200)
                .setSineAmplitude(this.getRandom()*0.02);
        }

    }

    return StarField
})();;

/* Source: client/renderer/texture/HexagonTexture.js */
"use strict";

window.HexagonTexture = function () {

    function HexagonTexture(graphics) {
        this.graphics = graphics;
    }

    HexagonTexture.prototype.getHexGridTexture = function (canvasSize, gridWidth, gridHeight, lineColor, fillColor, lineWidth) {
        return this.getTexture(this.renderHexGrid(canvasSize, lineColor, fillColor, lineWidth, true), gridWidth, gridHeight);
    };

    HexagonTexture.prototype.getHexTexture = function (canvasSize, lineColor, fillColor, lineWidth) {
        return this.getTexture(this.renderHexGrid(canvasSize, lineColor, fillColor, lineWidth), 1, 1);
    };

    HexagonTexture.prototype.renderHexGrid = function (canvasSize, lineColor, fillColor, lineWidth, repeat) {
        var scale = { x: 1, y: 1 };
        var width = canvasSize;
        var hl = width / 4 / Math.cos(30 / 180 * Math.PI);
        var a = window.HexagonMath.getHexA(hl);
        var b = window.HexagonMath.getHexB(hl);
        var x = b;

        var height = window.HexagonMath.getTextureHeight(hl);

        var canvas = createCanvas(width, height, false);
        var context = canvas.getContext("2d", { antialias: true });
        context.fillStyle = lineColor;
        context.strokeStyle = lineColor;
        context.fillStyle = fillColor;
        context.lineWidth = lineWidth;

        context.scale(scale.x, scale.y);

        if (repeat) {
            this.graphics.drawCenteredHexagon(context, x, 0, hl, true, true, true);
            this.graphics.drawCenteredHexagon(context, x * 3, 0, hl, true, true, true);
        }

        this.graphics.drawCenteredHexagon(context, x * 2, hl + a, hl, true, true, true);

        if (repeat) {
            this.graphics.drawCenteredHexagon(context, x, hl * 3, hl, true, true, true);
            this.graphics.drawCenteredHexagon(context, x * 3, hl * 3, hl, true, true, true);
        }

        var canvas2 = createCanvas(width, width, false);

        canvas2.getContext('2d', { antialias: true }).drawImage(canvas, 0, 0, width, height, 0, 0, width, width);

        return canvas2;
    };

    function createCanvas(width, height, debug) {
        return window.AbstractCanvas.create(width, height, debug);
    }
    /*
    HexagonTexture.prototype.renderNumberGrid = function (canvasSize, repeat) {
        var hexSize = canvasSize / 4;
        var width = canvasSize;
        var height = canvasSize;
    
        var canvas = createCanvas(width, height, false);
        var context = canvas.getContext("2d");
    
        var offsetX = hexSize * Math.cos(Math.PI / 6);
        var offsetY = hexSize * Math.sin(Math.PI / 6);
    
        // Loop through to draw hexagons
        for (var row = 0; row < height / (2 * hexSize); row++) {
            for (var col = 0; col < width / (2 * hexSize); col++) {
                var x = col * 2 * offsetX;
                var y = row * hexSize * 1.5;
    
                // Offset alternate rows
                if (col % 2 === 1) {
                    y += hexSize * 0.75;
                }
    
                this.graphics.drawCenteredHexagonNumber(context, x, y, hexSize);
            }
        }
    
        return canvas;
    };
    */
    HexagonTexture.prototype.getTexture = function (canvas, gridWidth, gridHeight) {

        if (gridWidth == undefined) {
            gridWidth = 1;
        }

        if (gridHeight == undefined) {
            gridHeight = 1;
        }

        var texture = new THREE.CanvasTexture(canvas);
        texture.colorSpace = THREE.SRGBColorSpace;
        texture.needsUpdate = true;
        texture.wrapS = THREE.RepeatWrapping;
        texture.wrapT = THREE.RepeatWrapping;
        texture.repeat.set(getHorizontalRepeat(gridWidth), getVerticalRepeat(gridHeight));

        texture.offset.set(0, 0.16666);

        return texture;
    };

    function getHorizontalRepeat(hexagons) {
        return 3 / 4 + (hexagons - 1) * 2 / 4;
    }

    function getVerticalRepeat(hexagons) {
        return 4 / 6 + (hexagons - 1) * 3 / 6;
    }

    return new HexagonTexture(window.graphics);
}();;

/* Source: client/UI/ShipTooltip.js */
'use strict';

window.ShipTooltip = function () {

    var HTML = '<div class="shipNameContainer">' + '<div class="namecontainer" style="border-bottom:1px solid white;margin-bottom:3px;"></div>' +
        '<div class="fire" style=";margin:3px 0px 3px 0px; padding:2px 0px 0px 0px;border-top:1px solid white;color:red; text-decoration: bold;"><span>TARGETING</span></div>' +
        '<div class="fire targeting"></div>' + '<div class="ballistics" style=";margin:3px 0px 3px 0px; padding:2px 0px 0px 0px;border-top:1px solid white;color:red;"><span>INCOMING:</span></div>' +
        '<div class="ballistics incoming"></div>' + '<div class="buttons"></div>' + '</div>';

    function ShipTooltip(selectedShip, ships, position, showTargeting, menu, hexagon, ballisticsMenu) {
        this.element = jQuery(HTML);
        this.ships = [].concat(ships);
        this.ships.sort(shipManager.hasBetterInitive); //so they're displayed in Ini order
        this.position = position;
        //TODO: selected ship might be destroyed
        this.selectedShip = selectedShip;
        this.showTargeting = showTargeting;
        this.hexagon = hexagon;
        this.menu = menu;
        this.ballisticsMenu = ballisticsMenu;

        this.element.on('mousedown mouseup mouseover mousemove mouseout', function (e) {
            e.preventDefault(); e.stopPropagation();
        });

        if (!menu) {
            this.element.on('mousedown mouseup mouseover mousemove mouseout', function (e) {
                this.destroy();
            }.bind(this));
        }

        if (ships.length > 1) {
            createForMultipleShips.call(this, this.ships);
        } else {
            createForSingleShip.call(this, this.ships[0]);
        }

        this.show();
    }

    ShipTooltip.prototype.show = function () {
        this.element.appendTo('body');
        this.element.show();
        positionElement(this.element, this.position);
    };

    ShipTooltip.prototype.reposition = function (position) {
        if (position) {
            this.position = position;
        }

        positionElement(this.element, this.position);

        return true;
    };

    ShipTooltip.prototype.destroy = function () {
        this.element.remove();
    };

    ShipTooltip.prototype.addEntryElement = function (value, condition) {
        if (condition === false || condition === 0 || condition === null) return;

        jQuery('<div class="entry"><span>' + value + '</span></div>').insertAfter(this.element.find('.namecontainer'));
    };

    ShipTooltip.prototype.update = function (ship, selectedShip) {
        if (selectedShip) {
            this.selectedShip = selectedShip;
            //this.showTargeting = shipManager.systems.selectedShipHasSelectedWeapons(this.selectedShip);
        }

        if (selectedShip && this.menu) {
            this.menu.selectedShip = selectedShip;
            this.menu.currentInfo = "";
        }

        jQuery(".buttons", this.element).html("");
        jQuery(".namecontainer", this.element).html("");
        jQuery(".fire", this.element).html("");
        jQuery(".entry", this.element).remove();
        jQuery(".incoming", this.element).html("");

        if (this.ships.length > 1) {
            createForMultipleShips.call(this, this.ships);
        } else {
            createForSingleShip.call(this, this.ships[0]);
        }
    };

    ShipTooltip.prototype.isForAnyOf = function (ships) {
        ships = [].concat(ships)

        if (this.ships.length > 1) {
            return false;
        }

        return this.ships.some(function (ship) {
            return ships.includes(ship)
        })

    }


    function createForSingleShip(ship) {
        var shipNameDisplay = ship.name;
        if (ship.mine) {
            var stealthSystem = shipManager.systems.getSystemByName(ship, "mineStealth");
            if (stealthSystem && !stealthSystem.isMineRevealed(ship)) {
                shipNameDisplay = "Mine";
            }
        }
        jQuery('<span class="name value ' + getAllyClass(ship) + '">' + shipNameDisplay + '</span>').appendTo(this.element.find('.namecontainer'));

        var jinking = shipManager.movement.getJinking(ship) * 5;
        var flightArmour = shipManager.systems.getFlightArmour(ship);

        //add info of flight-wide criticals!
        if (ship.flight === true) {
            //get first fighter in flight
            var firstFighter = shipManager.systems.getSystem(ship, 1);
            var sensorDown = shipManager.criticals.hasCritical(firstFighter, "tmpsensordown");
            if (sensorDown > 0) {
                sensorDown = sensorDown * 5;
                this.addEntryElement("<i>OB temporarily lowered by <b>" + sensorDown + "</b></i>", true);
            }
            var iniDown = shipManager.criticals.hasCritical(firstFighter, "tmpinidown");
            if (iniDown > 0) {
                iniDown = iniDown * 5;
                this.addEntryElement("<i>Initiative temporarily lowered by <b>" + iniDown + "</b></i>", true);
            }
        }

        if (ship.base && ship.movement[1]) {
            var direction;

            if (ship.movement[1].value === -1) {
                direction = "port";
            } else if (ship.movement[1].value === 1) {
                direction = "starboard";
            }

            if (direction) {
                this.addEntryElement("Rotation towards " + direction);
            }
        }


        /*condensed to one line
            this.addEntryElement('Evasion: -' + jinking + ' to hit', ship.flight === true && jinking > 0);	
            this.addEntryElement('Pivoting ' + shipManager.movement.isPivoting(ship), shipManager.movement.isPivoting(ship) !== 'no');
            this.addEntryElement('Rolling', shipManager.movement.isRolling(ship));
            this.addEntryElement('Rolled', shipManager.movement.isRolled(ship));
        */
        var toDisplay = '';
        var rollPivotModifier = 0;
        //if (ship.flight === true && jinking > 0) toDisplay += 'Evasion: -' + jinking + ' to hit; ';
        if (jinking > 0) toDisplay += 'Evasion: -' + jinking + ' to hit; ';    //Ships can jink too now - DK Oct 2025
        if (shipManager.movement.isPivoting(ship) !== 'no') toDisplay += 'Pivoting; ';
        if (ship.agile && (!ship.flight)) {
            if (shipManager.movement.hasRolled(ship)) {
                toDisplay += 'Has rolled; ';
                if (!ship.ignoreManoeuvreMods) rollPivotModifier -= 15;
            }
        } else if ((!ship.flight)) {
            if (shipManager.movement.isRolling(ship)) {
                toDisplay += 'Rolling; ';
                if (!ship.ignoreManoeuvreMods) rollPivotModifier -= 15;
            }
        }
        if ((!ship.flight) && shipManager.movement.isRolled(ship)) toDisplay += 'Rolled; '; //fighters don't roll, no point looking for it
        if ((!ship.flight) && shipManager.movement.isHalfPhased(ship)) { //fighters don't half phase, no point looking for it
            toDisplay += 'Half-Phased; ';
            rollPivotModifier -= 50;
        }
        if (ship.trueStealth) {
            if (gamedata.gamephase == -1 && shipManager.getTurnDeployed(ship) == gamedata.turn) {
                toDisplay += '<span style="color:limegreen;">Deploying</span>; '; //Always say undetected on Deployment phase.  
            } else {
                var isShipDetected = shipManager.isDetected(ship);
                var stealthSys = null;

                if (ship.mine) {
                    stealthSys = shipManager.systems.getSystemByName(ship, "mineStealth");
                } else if (ship.faction == "Torvalus Speculators") {
                    stealthSys = shipManager.systems.getSystemByName(ship, "ShadingField");
                } else if (shipManager.getSpecialAbilityStealth(ship, "Cloaking")) {
                    stealthSys = shipManager.systems.getSystemByName(ship, "CloakingDevice");
                } else if (shipManager.getSpecialAbilityStealth(ship, "Stealth")) {
                    stealthSys = shipManager.systems.getSystemByName(ship, "stealth");
                }

                if (!isShipDetected && ship.team == gamedata.getPlayerTeam()) {
                    if (stealthSys) {
                        if (Array.isArray(stealthSys.detected) && stealthSys.detected.length > 0) {
                            isShipDetected = true;
                        } else if (stealthSys.detected === true) {
                            isShipDetected = true;
                        } else if (Array.isArray(stealthSys.detectedNew) && stealthSys.detectedNew.length > 0) {
                            isShipDetected = true;
                        } else if (stealthSys.detectedNew === true) {
                            isShipDetected = true;
                        }
                    }
                }

                if (isShipDetected) {
                    var detectedTeamsStr = "";
                    if (ship.team == gamedata.getPlayerTeam()) { //Only own player needs to see full team list that's detected their ship.
                        // Check if we have more than 2 teams in the game
                        var uniqueTeams = [];
                        for (var i in gamedata.slots) {
                            var team = parseInt(gamedata.slots[i].team, 10);
                            if (team > 0 && !uniqueTeams.includes(team)) {
                                uniqueTeams.push(team);
                            }
                        }

                        if (uniqueTeams.length > 2) {
                            var detectedArray = [];
                            if (stealthSys && Array.isArray(stealthSys.detectedNew)) {
                                detectedArray = stealthSys.detectedNew;
                            } else if (stealthSys && Array.isArray(stealthSys.detected)) {
                                detectedArray = stealthSys.detected;
                            }

                            if (detectedArray.length > 0) {
                                // Ensure unique team numbers
                                var uniqueDetectedTeams = [];
                                for (var i = 0; i < detectedArray.length; i++) {
                                    var detectedTeam = parseInt(detectedArray[i], 10);
                                    if (detectedTeam > 0 && !uniqueDetectedTeams.includes(detectedTeam)) {
                                        uniqueDetectedTeams.push(detectedTeam);
                                    }
                                }

                                // Sort team numbers for readability
                                uniqueDetectedTeams.sort(function (a, b) { return a - b; });

                                if (uniqueDetectedTeams.length > 0) {
                                    detectedTeamsStr = " (Teams: " + uniqueDetectedTeams.join(", ") + ")";
                                }
                            }
                        }
                    }

                    toDisplay += '<span style="color:red;">Detected' + detectedTeamsStr + '</span>; '; //Notify player that their Stealth ship is detected.
                } else {
                    toDisplay += '<span style="color:limegreen;">Undetected</span>; '; //Notify player that their Stealth ship is detected.            
                }
            }
        }

        if (gamedata.gamephase == 3) {
            if (Object.values(ship.skinDancing).includes(true)) {
                toDisplay += '<span style="color:limegreen;">Skin Dancing</span>; '; //Notify player that unit is skin dancing this turn.                  
            } else if (Object.values(ship.skinDancing).includes("Aborted")) {
                toDisplay += '<span style="color:orange;">Skin Dance Aborted</span>; '; //Notify player that unit is skin dancing this turn.  
            } else if (Object.values(ship.skinDancing).includes("Failed")) {
                toDisplay += '<span style="color:red;">Failed Skin Dancing</span>; '; //Notify player that unit is skin dancing this turn.  
            }
        }

        if (ship.flight === true) {
            if (shipManager.movement.hasCombatPivoted(ship) && (!ship.ignoreManoeuvreMods)) rollPivotModifier -= 5;
        } else if (ship.osat) {
            if (shipManager.movement.hasTurned(ship)) rollPivotModifier -= 5;
        } else {
            if (shipManager.movement.hasPivotedForShooting(ship) && (!ship.ignoreManoeuvreMods)) rollPivotModifier -= 15;
        }
        if (rollPivotModifier != 0) toDisplay += 'Firing modifier: ' + rollPivotModifier; //display firing modifier from roll/pivot/combat pivot


        if (toDisplay != '') toDisplay = '<b><i>' + toDisplay + '</i></b>';
        this.addEntryElement(toDisplay, toDisplay != '');

        /*condensed to one line
        this.addEntryElement("Ballistic navigator aboard", ship.hasNavigator === true);
        this.addEntryElement("Escorting ships in same hex", shipManager.isEscorting(ship));
        */
        toDisplay = '';
        if (ship.hasNavigator === true) toDisplay += 'Navigator; ';
        var listEscorting = shipManager.listEscorting(ship);
        if (listEscorting != '') {
            toDisplay += '<span class="escorting">Escorting: </span>';
            //list of unit names
            toDisplay += listEscorting;
        }
        this.addEntryElement(toDisplay, toDisplay != '');

        if (ship.mine) {
            if (gamedata.isMyorMyTeamShip(ship)) toDisplay = 'Signature: ' + ship.signature;
            this.addEntryElement(toDisplay);
        } else {
            //this.addEntryElement("Iniative Order: " + shipManager.getIniativeOrder(ship) + "    (D100 + " + ship.iniativebonus + ")");
            this.addEntryElement("Ini Order: " + shipManager.getIniativeOrder(ship) + " (total " + ship.iniative + "): base " + ship.iniativebonus + "; mod " + ship.iniativeadded);

            /*miscellanous info - once inserted, now disappeared; if it's needed, look for source code in Abbai branch!
            toDisplay = shipManager.systems.getMisc(ship);
            this.addEntryElement(toDisplay, toDisplay!=''); //miscellanous info from systems - special information o be shown here
            */

            //this.addEntryElement('Current turn delay: ' + shipManager.movement.calculateCurrentTurndelay(ship));
            var currDelay = shipManager.movement.calculateCurrentTurndelay(ship)
            var speed = shipManager.movement.getSpeed(ship);
            var baseTurnCost = ship.turncost;
            if (ship.submarine && shipManager.movement.isGoingBackwards(ship)) baseTurnCost = baseTurnCost * 1.33;
            var turncost = Math.ceil(speed * baseTurnCost);
            var turnDelayCost = Math.ceil(speed * ship.turndelaycost);

            this.addEntryElement('Pivot cost: ' + ship.pivotcost + ' Roll cost: ' + ship.rollcost, ship.flight !== true);
            this.addEntryElement('Pivot cost: ' + ship.pivotcost + ' Combat pivot cost: ' + Math.ceil(ship.pivotcost * 1.5), ship.flight === true);
            toDisplay = ''; //display Agile status
            if (ship.agile) toDisplay = ', Agile';
            this.addEntryElement('Turn Cost: ' + turncost + ' (' + ship.turncost + '); Turn Delay: ' + turnDelayCost + ' (' + ship.turndelaycost + ')' + toDisplay);

            var thrustRemaining = Math.max(shipManager.movement.getRemainingEngineThrust(ship), 0);//EngineShorted can make this go negative.

            toDisplay = 'Thrust: ' + thrustRemaining + '/' + shipManager.movement.getFullEngineThrust(ship);//thrust: remaining/full
            this.addEntryElement(toDisplay, toDisplay != '');
            //this.addEntryElement('Unused thrust: ' + shipManager.movement.getRemainingEngineThrust(ship), ship.flight || gamedata.gamephase === 2);

            toDisplay = 'Speed: ' + shipManager.movement.getSpeed(ship);
            if (currDelay > 0) toDisplay += ' (delay ' + currDelay + ')';
            toDisplay += ' (acc cost: ' + ship.accelcost + ')';
            this.addEntryElement(toDisplay);
            this.addEntryElement('Armor (F/S/A): ' + flightArmour, ship.flight === true);

            if (this.selectedShip) {
                if (!gamedata.isMyShip(ship)) {
                    this.addEntryElement('OEW: ' + ew.getOffensiveEW(this.selectedShip, ship), this.selectedShip !== ship && ship.flight !== true && this.selectedShip.flight !== true);
                }

                if (shipManager.isElint(this.selectedShip)) {
                    if (shipManager.hasSpecialAbility(this.selectedShip, "ConstrainedEW")) {//Mindrider ships have less efficient ELINT abilities - DK 19.07.24.            	
                        this.addEntryElement('DIST: ' + ew.getOffensiveEW(this.selectedShip, ship, "DIST") / 4, this.selectedShip !== ship && ship.flight !== true);
                    } else {
                        this.addEntryElement('DIST: ' + ew.getOffensiveEW(this.selectedShip, ship, "DIST") / 3, this.selectedShip !== ship && ship.flight !== true);
                    }
                }
            }

            var dewValue = ew.getSupportedDEW(ship).toFixed(2);
            //if (ew.getSupportedDEW(ship)) {//Amended because Mindrider Constrained EW can create over 2 decimal places in Ship Tooltip! DK - 20.7.24	
            if (dewValue > 0) {//Amended because Mindrider Constrained EW can create over 2 decimal places in Ship Tooltip! DK - 20.7.24 
                this.addEntryElement('Support DEW: ' + dewValue, ship.flight !== true);
            }

            var MDEW = ew.getDetectMEW(ship);
            if (MDEW > 0) {//Amended because Mindrider Constrained EW can create over 2 decimal places in Ship Tooltip! DK - 20.7.24	
                this.addEntryElement('Detect Mines: ' + MDEW);
            }

            if (shipManager.isElint(ship)) {
                if (gamedata.isStealthPresent) this.addEntryElement('Detect Stealth: ' + ew.getEWByType('Detect Stealth', ship), ship.flight !== true);
                this.addEntryElement('Blanket DEW: ' + ew.getEWByType('BDEW', ship), ship.flight !== true);
            }

            this.addEntryElement('DEW: ' + ew.getDefensiveEW(ship) + ' CCEW: ' + ew.getCCEW(ship), ship.flight !== true);
        }
        //Amended because Mindrider Constrained EW can create over 2 decimal places in Ship Tooltip! DK - 20.7.24
        var fDef = weaponManager.calculateBaseHitChange(ship, ship.forwardDefense) * 5;
        fDef = parseFloat(fDef.toFixed(2));
        var sDef = weaponManager.calculateBaseHitChange(ship, ship.sideDefense) * 5;
        sDef = parseFloat(sDef.toFixed(2));

        this.addEntryElement("Defence (F/S): " + fDef + "(" + ship.forwardDefense * 5 + ") / " + sDef + "(" + ship.sideDefense * 5 + ")%");

        if (this.selectedShip && this.selectedShip !== ship) {
            var dis = mathlib.getDistanceBetweenShipsInHex(this.selectedShip, ship);
            this.addEntryElement('DISTANCE: ' + dis + ' hexes');
        }

        if (gamedata.rules && gamedata.rules.friendlyFire === 1) {
            if (this.selectedShip && this.showTargeting && this.selectedShip.id != ship.id) {
                weaponManager.targetingShipTooltip(this.selectedShip, ship, this.element, null);
                this.element.find(".fire").css({ "display": "block", "visibility": "visible" });
            } else {
                this.element.find(".fire").css("display", "none");
            }
        } else {
            if (this.selectedShip && gamedata.isEnemy(ship, this.selectedShip) && this.showTargeting) { //Old version before allied targeting
                weaponManager.targetingShipTooltip(this.selectedShip, ship, this.element, null);
                this.element.find(".fire").css({ "display": "block", "visibility": "visible" });
            } else if (this.selectedShip && gamedata.canTargetAlly(ship) && this.showTargeting) {//30 June 2024 - DK - Added for Ally targeting.
                weaponManager.targetingShipTooltip(this.selectedShip, ship, this.element, null);
                this.element.find(".fire").css({ "display": "block", "visibility": "visible" });
            } else {
                this.element.find(".fire").css("display", "none");
            }
        }

        this.ballisticsMenu.renderTo(ship, this.element);

        if (this.menu) {
            this.menu.renderTo(jQuery(".buttons", this.element), this);
        }
    }

    function createForMultipleShips(ships) {
        ships.forEach(function (ship, i) {
            var comma = i < ships.length - 1 ? ',' : '';
            var shipNameDisplay = ship.name;
            if (ship.mine) {
                var stealthSystem = shipManager.systems.getSystemByName(ship, "mineStealth");
                if (stealthSystem && !stealthSystem.isMineRevealed(ship)) {
                    shipNameDisplay = "Mine";
                }
            }
            jQuery('<span class="name value ' + getAllyClass(ship) + '">' + shipNameDisplay + comma + ' </span>').appendTo(this.element.find('.namecontainer'));

            $(".ballistics", this.element).hide();
        }, this);
        this.addEntryElement("Zoom closer, or click to interact");
    }

    function showBallisticsTooltip(ballistics) { }

    function positionElement(element, position) {
        if (position instanceof hexagon.Offset) {
            position = window.coordinateConverter.fromHexToViewport(position);
        } else {
            position = window.coordinateConverter.fromGameToViewPort(position);
        }

        var yOffset = window.coordinateConverter.getHexHeightViewport() / 2;

        if (yOffset > 100) {
            yOffset = 100;
        }

        if (yOffset < 20) {
            yOffset = 20;
        }

        element.css("left", position.x - (element.width() + 30) / 2 + "px").css("top", position.y + yOffset + "px");
    }

    function getAllyClass(ship) {
        /* if(ship.shipSizeClass == 5){
             return 'terrain'; //Return a neutral white colour for Terrain.
         }else{
             return gamedata.isMyOrTeamOneShip(ship) ?  'ally' : 'enemy';
         }*/
        //Let's make allied team ships blue text, and terrain white - DK May 2025
        return gamedata.isTerrain(ship.shipSizeClass, ship.userid) ? 'terrain' : (gamedata.isMyShip(ship) ? 'mine' : (gamedata.isMyorMyTeamShip(ship) ? 'ally' : 'enemy'));
    }

    return ShipTooltip;
}();
;

/* Source: client/UI/SelectFromShips.js */
'use strict';

window.SelectFromShips = function () {

    var HTML = '<div class="shipNameContainer"></div>';

    function ShipTooltip(selectedShip, ships, payload, phaseStrategy) {
        this.element = jQuery(HTML);
        this.ships = [].concat(ships);
        //this.ships.sort(shipManager.hasBetterInitive); //so they're displayed in Ini order
        this.ships.sort(shipManager.hasWorseInitiveSort); //actualy make it so highest Ini is on top
        this.position = payload.hex;
        this.payload = payload;
        this.selectedShip = selectedShip;
        this.phaseStrategy = phaseStrategy;

        this.element.on('mousedown', function (e) {
            e.preventDefault();
        });
        this.element.on('mouseup', function (e) {
            e.preventDefault();
        });
        this.element.on('mouseover', function (e) {
            e.preventDefault(); e.stopPropagation();
        });
        this.element.on('mousemove', function (e) {
            e.preventDefault();
        });
        this.element.on('mouseout', function (e) {
            e.preventDefault(); e.stopPropagation();
        });

        create.call(this);

        this.show();
    }

    ShipTooltip.prototype.show = function () {
        this.element.appendTo('body');
        this.element.show();
        positionElement(this.element, this.position);
    };

    ShipTooltip.prototype.reposition = function (position) {
        if (position) {
            this.position = position;
        }

        positionElement(this.element, this.position);

        return true;
    };

    ShipTooltip.prototype.destroy = function () {
        this.element.remove();
    };

    ShipTooltip.prototype.addEntryElement = function (value, condition) {
        if (condition === false || condition === 0 || condition === null) return;

        jQuery('<div class="entry"><span>' + value + '</span></div>').insertAfter(this.element.find('.namecontainer'));
    };

    ShipTooltip.prototype.update = function (ship, selectedShip) {

    };

    function create() {
        console.log("CREATE select form ships", this.ships)
        
        // --- INJECT CUSTOM "DEPLOY HERE" BUTTON DURING DEPLOYMENT PHASE ---
        if (gamedata.gamephase == -1 && this.phaseStrategy.selectedShip) {
            // Guarantee we don't present the deployment option if the unit is ALREADY right here
            var rawPos = shipManager.getShipPosition(this.phaseStrategy.selectedShip);
            var parsedSelectedPos = new hexagon.Offset(rawPos);
            
            // Replicate the exact isBlocked occupancy check from DeploymentPhaseStrategy to explicitly deny the button appearing when dropping onto illegal stacked hexes
            var isBlocked = false;
            var shipsInHex = shipManager.getShipsInSameHex(this.phaseStrategy.selectedShip, this.payload.hex);
            
            var hasTerrain = shipsInHex.some(function(s) {
                return gamedata.isTerrain(s.shipSizeClass, s.userid) || (s.Huge > 0 && s.Huge <= 3);
            });
            
            if (hasTerrain) {
                isBlocked = true;
            } else if (!(this.phaseStrategy.selectedShip.mine || this.phaseStrategy.selectedShip.flight)) {
                isBlocked = shipsInHex.some(function(s) { return !(s.mine || s.flight); });
            }
            
            if (!isBlocked && (!parsedSelectedPos || parsedSelectedPos.q !== this.payload.hex.q || parsedSelectedPos.r !== this.payload.hex.r)) {
                var selectedName = this.phaseStrategy.selectedShip.name;
                var deployButton = jQuery(
                    '<div class="name-value-button-ally">DEPLOY ' + selectedName.toUpperCase() + ' HERE</div>'
                ).on('click', function () {
                    this.phaseStrategy.onHexClicked(this.payload);
                    this.destroy();
                }.bind(this));
                
                this.element.append(deployButton);
            }
        }
        // ------------------------------------------------------------------

        this.ships.forEach(function (ship) {
            var deployedText = "";
            var deployTurn = shipManager.getTurnDeployed(ship);
            //if(shipManager.getTurnDeployed(ship) > gamedata.turn)  deployedText = '<span class="not-deployed">(Not Deployed)</span> ';
            if (deployTurn > gamedata.turn) deployedText = '<span class="not-deployed"> (Deploys Turn ' + deployTurn + ')</span> ';

            if (ship.flight) {
                var noOfFighters = 0;
                ship.systems.forEach(ftr => {
                    if (!shipManager.systems.isDestroyed(ship, ftr)) {
                        noOfFighters++;
                    }
                });
                var name = jQuery(
                    '<div class="name value button ' + getAllyClass(ship) + '">' + '(' + noOfFighters + ') ' + ship.name + deployedText + ' </div>'
                )
                    .on('click', function () {
                        if (gamedata.gamephase === -1) {
                            if (this.phaseStrategy.selectedShip) {
                                this.phaseStrategy.deselectShip(this.phaseStrategy.selectedShip);
                            }
                            this.phaseStrategy.selectShip(ship, this.payload);
                            this.destroy();
                        } else {
                            this.phaseStrategy.onShipClicked(ship, this.payload);
                            if (this.phaseStrategy.selectedShip && this.phaseStrategy.selectedShip.id === ship.id) {
                                this.destroy();
                            }
                        }
                    }.bind(this))
                    .on('mouseover', function () { this.phaseStrategy.onMouseOverShip(ship, this.payload) }.bind(this))
                    .on('mouseout', function () { this.phaseStrategy.onMouseOutShips(ship, this.payload) }.bind(this))
                name.contextmenu(function (e) {
                    e.preventDefault();
                    e.stopPropagation();
                    this.phaseStrategy.onShipRightClicked(ship, this.payload)
                }.bind(this))
                this.element.append(name)

            } else {
                var name = jQuery('<div class="name value button ' + getAllyClass(ship) + '">' + ship.name + deployedText + ' </div>')
                    .on('click', function () {
                        if (gamedata.gamephase === -1) {
                            if (this.phaseStrategy.selectedShip) {
                                this.phaseStrategy.deselectShip(this.phaseStrategy.selectedShip);
                            }
                            this.phaseStrategy.selectShip(ship, this.payload);
                            this.destroy();
                        } else {
                            this.phaseStrategy.onShipClicked(ship, this.payload);
                            if (this.phaseStrategy.selectedShip && this.phaseStrategy.selectedShip.id === ship.id) {
                                this.destroy();
                            }
                        }
                    }.bind(this))
                    .on('mouseover', function () { this.phaseStrategy.onMouseOverShip(ship, this.payload) }.bind(this))
                    .on('mouseout', function () { this.phaseStrategy.onMouseOutShips(ship, this.payload) }.bind(this))
                name.contextmenu(function (e) {
                    e.preventDefault();
                    e.stopPropagation();
                    this.phaseStrategy.onShipRightClicked(ship, this.payload)
                }.bind(this))
                this.element.append(name)
            }
        }, this)
    }

    function showBallisticsTooltip(ballistics) { }

    function positionElement(element, position) {
        if (position instanceof hexagon.Offset) {
            position = window.coordinateConverter.fromHexToViewport(position);
        } else {
            position = window.coordinateConverter.fromGameToViewPort(position);
        }

        var yOffset = window.coordinateConverter.getHexHeightViewport() / 2;

        if (yOffset > 100) {
            yOffset = 100;
        }

        if (yOffset < 20) {
            yOffset = 20;
        }

        element.css("left", position.x - (element.width() + 30) / 2 + "px").css("top", (position.y - yOffset - element.height()) + "px");
    }

    function getAllyClass(ship) {
        /*
        if(ship.shipSizeClass == 5){
            return 'terrain'; //Return a neutral white colour for Terrain.
        }else{
            return gamedata.isMyOrTeamOneShip(ship) ?  'ally' : 'enemy';
        }   
        */
        return gamedata.isTerrain(ship.shipSizeClass, ship.userid) ? 'terrain' : (gamedata.isMyShip(ship) ? 'mine' : (gamedata.isMyorMyTeamShip(ship) ? 'ally' : 'enemy'))
    }

    return ShipTooltip;
}();
