"use strict";

window.ShipMovementCallbacks = function () {

    function ShipMovementCallbacks(ship, updateCallback) {
        this.ship = ship;
        this.updateCallback = updateCallback;
    }

    ShipMovementCallbacks.prototype.cancelCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.deleteMove(this.ship);		
		if (event.which == 3) while (shipManager.movement.hasDeletableMovements(this.ship)){//r-click
			shipManager.movement.deleteMove(this.ship);	
		}
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.morejinkCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.doJink(this.ship, 1);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.lessjinkCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.doJink(this.ship, -1);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.halfphaseCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.doHalfPhase(this.ship);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.morecontractionCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.doContraction(this.ship, 1);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.lesscontractionCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.doContraction(this.ship, -1);
        this.updateCallback({ ship: this.ship });
    };
	
    ShipMovementCallbacks.prototype.accelCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.changeSpeed(this.ship, true);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.deaccCallback = function (e) {
        e.stopPropagation();
        shipManager.movement.changeSpeed(this.ship, false);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.rollCallback = function (e) {
        e.stopPropagation();

        shipManager.movement.doRoll(this.ship);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.emergencyrollCallback = function (e) {
        e.stopPropagation();

        shipManager.movement.doEmergencyRoll(this.ship);
        this.updateCallback({ ship: this.ship });
    };
    
    ShipMovementCallbacks.prototype.pivotrightCallback = function (e) {
        e.stopPropagation();
        this.pivotCallback(e, true);
    };

    ShipMovementCallbacks.prototype.pivotleftCallback = function (e) {
        e.stopPropagation();
        this.pivotCallback(e, false);
    };

    ShipMovementCallbacks.prototype.pivotCallback = function (e, right) {
        if (UI.shipMovement.checkUITimeout()) return false;

        shipManager.movement.doPivot(this.ship, right);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.rotateleftCallback = function (e) {
        e.stopPropagation();
        this.rotateCallback(e, true);
    };

    ShipMovementCallbacks.prototype.rotaterightCallback = function (e) {
        e.stopPropagation();
        this.rotateCallback(e, false);
    };

    ShipMovementCallbacks.prototype.rotateCallback = function (e, right) {
        e.stopPropagation();
        if (this.ship.base) {
            shipManager.movement.pickRotation(this.ship, right);
            this.updateCallback({ ship: this.ship });
        }
    };

    ShipMovementCallbacks.prototype.sliprightCallback = function (e) {
        e.stopPropagation();
        this.slipCallback(e, true);
    };

    ShipMovementCallbacks.prototype.slipleftCallback = function (e) {
        e.stopPropagation();
        this.slipCallback(e, false);
    };

    ShipMovementCallbacks.prototype.slipCallback = function (e, right) {
        shipManager.movement.doSlip(this.ship, right);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.turnrightCallback = function (e) {
        e.stopPropagation();
        this.turnCallback(e, true);
    };

    ShipMovementCallbacks.prototype.turnleftCallback = function (e) {
        e.stopPropagation();
        this.turnCallback(e, false);
    };

    ShipMovementCallbacks.prototype.turnCallback = function (e, right) {
        shipManager.movement.doTurn(this.ship, right);
        this.updateCallback({ ship: this.ship });
    };

    ShipMovementCallbacks.prototype.graviticTurnRightCallback = function (e) {
        e.stopPropagation();
        this.graviticTurnCallback(e, true);
    };

    ShipMovementCallbacks.prototype.graviticTurnLeftCallback = function (e) {
        e.stopPropagation();
        this.graviticTurnCallback(e, false);
    };    

    ShipMovementCallbacks.prototype.graviticTurnCallback = function (e, right) {
        shipManager.movement.doGraviticTurn(this.ship, right);
        this.updateCallback({ ship: this.ship });
    };    

    ShipMovementCallbacks.prototype.moveCallback = function (e) {
        e.stopPropagation();

        if (UI.shipMovement.checkUITimeout()) return false;
		if (event.which == 3){ //r-click - move for all remaining movement
			shipManager.movement.doMoveFully(this.ship);
		}else{
			shipManager.movement.doMove(this.ship);
		}
        this.updateCallback({ ship: this.ship });
    };
	
    ShipMovementCallbacks.prototype.turnIntoPivotCallback = function (e, right) {
        e.stopPropagation();

        shipManager.movement.doIntoPivotTurn(this.ship, right);
        this.updateCallback({ ship: this.ship });
    };

    return ShipMovementCallbacks;
}();;

/* Source: client/model/hexagon/Cube.js */
'use strict';

var _typeof = typeof Symbol === "function" && typeof Symbol.iterator === "symbol" ? function (obj) { return typeof obj; } : function (obj) { return obj && typeof Symbol === "function" && obj.constructor === Symbol && obj !== Symbol.prototype ? "symbol" : typeof obj; };

if (typeof window.hexagon === 'undefined') window.hexagon = {};

window.hexagon.Cube = function () {
    function Cube(x, y, z) {
        if ((typeof x === 'undefined' ? 'undefined' : _typeof(x)) === 'object') {
            var cube = x;
            this.x = this._formatNumber(cube.x);
            this.y = this._formatNumber(cube.y);
            this.z = this._formatNumber(cube.z);
        } else {
            this.x = this._formatNumber(x);
            this.y = this._formatNumber(y);
            this.z = this._formatNumber(z);
        }

        this._validate();
    }

    Cube.PRECISION = 4;

    Cube.prototype.round = function () {
        if (this.x % 1 === 0 && this.y % 1 === 0 && this.z % 1 === 0) {
            return this;
        }

        var rx = Math.round(this.x);
        var ry = Math.round(this.y);
        var rz = Math.round(this.z);

        var x_diff = Math.abs(rx - this.x);
        var y_diff = Math.abs(ry - this.y);
        var z_diff = Math.abs(rz - this.z);

        if (x_diff > y_diff && x_diff > z_diff) {
            rx = -ry - rz;
        } else if (y_diff > z_diff) {
            ry = -rx - rz;
        } else {
            rz = -rx - ry;
        }

        return new hexagon.Cube(rx, ry, rz);
    };

    Cube.prototype._validate = function () {
        if (Math.abs(this.x + this.y + this.z) > 0.001) {
            throw new Error("Invalid Cube coordinates: (" + this.x + ", " + this.y + ", " + this.z + ")");
        }
    };

    Cube.prototype.neighbours = [{ x: 1, y: -1, z: 0 }, { x: 1, y: 0, z: -1 }, { x: 0, y: 1, z: -1 }, { x: -1, y: 1, z: 0 }, { x: -1, y: 0, z: 1 }, { x: 0, y: -1, z: 1 }];

    Cube.prototype.getNeighbours = function () {
        var neighbours = [];

        this.neighbours.forEach(function (neighbour) {
            neighbours.push(this.add(neighbour));
        }, this);

        return neighbours;
    };

    Cube.prototype.moveToDirection = function (direction) {
        return this.add(this.neighbours[direction]);
    };

    Cube.prototype.add = function (cube) {
        return new hexagon.Cube(this.x + cube.x, this.y + cube.y, this.z + cube.z);
    };

    Cube.prototype.subtract = function (cube) {
        return new hexagon.Cube(this.x - cube.x, this.y - cube.y, this.z - cube.z);
    };

    Cube.prototype.scale = function (scale) {
        return new hexagon.Cube(this.x * scale, this.y * scale, this.z * scale);
    };

    Cube.prototype.distanceTo = function (cube) {
        return Math.max(Math.abs(this.x - cube.x), Math.abs(this.y - cube.y), Math.abs(this.z - cube.z));
    };

    Cube.prototype.equals = function (cube) {
        return this.x === cube.x && this.y === cube.y && this.z === cube.z;
    };

    Cube.prototype.getFacing = function (neighbour) {
        var index = -1;

        var delta = neighbour.subtract(this);

        this.neighbours.some(function (hex, i) {
            if (delta.equals(hex)) {
                index = i;
                return true;
            }
        });

        return index;
    };

    Cube.prototype.toOffset = function () {
        var q = this.x + (this.z + (this.z & 1)) / 2;
        var r = this.z;

        var Offset = hexagon.Offset;

        return new Offset(q, r); //EVEN_R
    };

    /*
        Cube.prototype.toOffset = function()
        {
            var q = this.x + (this.z - (this.z & 1)) / 2;
            var r = this.z;
    
            return new hexagon.Offset(q, r); //ODD_R
        };
    */
    Cube.prototype.toString = function () {
        return "(" + this.x + "," + this.y + "," + this.z + ")";
    };

    Cube.prototype._formatNumber = function (number) {
        return parseFloat(number.toFixed(hexagon.Cube.PRECISION));
    };

    return Cube;
}();;

/* Source: client/model/hexagon/Offset.js */
'use strict';

var _typeof = typeof Symbol === "function" && typeof Symbol.iterator === "symbol" ? function (obj) { return typeof obj; } : function (obj) { return obj && typeof Symbol === "function" && obj.constructor === Symbol && obj !== Symbol.prototype ? "symbol" : typeof obj; };

if (typeof window.hexagon === 'undefined') window.hexagon = {};

window.hexagon.Offset = function () {

    function Offset(q, r) {
        if ((typeof q === 'undefined' ? 'undefined' : _typeof(q)) === 'object') {
            var offset = q;
            this.q = offset.q;
            this.r = offset.r;
        } else {
            this.q = q;
            this.r = r;
        }
    }

    Offset.prototype.neighbours = [[{ q: 1, r: 0 }, { q: 1, r: -1 }, { q: 0, r: -1 }, { q: -1, r: 0 }, { q: 0, r: 1 }, { q: 1, r: 1 }], [{ q: 1, r: 0 }, { q: 0, r: -1 }, { q: -1, r: -1 }, { q: -1, r: 0 }, { q: -1, r: 1 }, { q: 0, r: 1 }]];

    Offset.prototype.getNeighbours = function () {
        var neighbours = [];

        this.neighbours[this.r & 1].forEach(function (neighbour) {
            neighbours.push(this.add(neighbour));
        }, this);

        return neighbours;
    };

    Offset.prototype.add = function (offset) {
        var q = this.q + offset.q;
        var r = this.r + offset.r;

        return new hexagon.Offset(q, r);
    };

    Offset.prototype.equals = function (offset) {
        return this.q === offset.q && this.r === offset.r;
    };

    Offset.prototype.getNeighbourAtDirection = function (direction) {
        var neighbours = this.getNeighbours();

        return neighbours[direction];
    };

    Offset.prototype.distanceTo = function (target) {
        return this.toCube().distanceTo(target.toCube());
    };

    Offset.prototype.toCube = function () {

        var x = this.q - (this.r + (this.r & 1)) / 2;
        var z = this.r;
        var y = -x - z;

        /*
        var x, y, z;
        switch (this.layout) {
            case Offset.ODD_R:
                x = this.q - (this.r - (this.r & 1)) / 2;
                z = this.r;
                y = -x - z;
                break;
            case Offset.EVEN_R:
                x = this.q - (this.r + (this.r&1)) / 2;
                z = this.r;
                y = -x - z;
                break;
        }
        */

        return new hexagon.Cube(x, y, z).round();
    };

    return Offset;
}();;

/* Source: client/gameRules/SimultaneousMovementRule.js */
window.SimultaneousMovementRule = (function(){

    function SimultaneousMovementRule() {

    }

    SimultaneousMovementRule.prototype.getShipCategoryIndex = function (ship) {
        if (! gamedata.rules.initiativeCategories) {
            return null;
        }

        var categories = getGategories(gamedata.rules.initiativeCategories);

        var index = null;
        categories.find(function(category, i) {
            if (ship.iniative === category) {
                index = i;
                return true;
            }
            return false;
        })


        return categories.length - index;
    }


    SimultaneousMovementRule.prototype.isActiveMovementShip = function(ship) {
        var active = gamedata.getActiveShips();
        if (active.length === 0) {
            return null;
        }

        var ini = active.pop().iniative;

        return ship.iniative === ini;
    }

    SimultaneousMovementRule.prototype.isNotYetMovedShip = function(ship) {
        var active = gamedata.getActiveShips();
        if (active.length === 0) {
            return null;
        }

        var ini = active.pop().iniative;

        return ship.iniative > ini;
    }
    
    function getGategories(number) {
        var categories = [];
        var step = Math.floor(200 / number);

        while (number--) {
            categories.push(step * number);
        }
        
        return categories;
    }

    return new SimultaneousMovementRule();
})();;

/* Source: client/UI/botPanel.js */
"use strict";

jQuery(function () {
	jQuery("#logUI div").on("click", window.botPanel.onLogUIClicked)


	$("#expandBotPanel").click(function () {
		var logContainer = $("#logcontainer");

		logContainer.toggleClass('large');

		// Hide iniGui if logcontainer is large
		if (logContainer.hasClass('large')) {
			$(iniGui).addClass("closed");
			$(backDiv).addClass("closed");
			$(backDiv).data("on", 0);
			document.getElementById("iniSlider").src = "img/pullOut.png";
		} else {
			// If not large, ensure it behaves normally
			$(iniGui).removeClass("closed");
			$(backDiv).removeClass("closed");
			$(backDiv).data("on", 1);

			// Clean up any potential lingering inline styles
			$("#iniGui").css("display", "");
			$("#backDiv").css("margin-left", "");

			document.getElementById("iniSlider").src = "img/pullIn.png";
		}

		// Manually create a fake element with the right data-select
		var fakeElement = $("<div>").data("select", "#log");
		// Call onLogUIClicked with that fake element as "this"
		window.botPanel.onLogUIClicked.call(fakeElement);
	});
});

window.botPanel = {

	updateCallback: null,
	onLogUIClicked: function onLogUIClicked(e) {

		var e = $(this);
		$(".logUiEntry").removeClass("selected");
		e.addClass("selected");

		$(".logPanelEntry").hide();

		var select = e.data("select");
		var e = $(select);
		e.show();
		e.trigger("onshow");
	},

	onShipStatusChanged: function onShipStatusChanged(ship) {
		if (botPanel.updateCallback) {
			botPanel.updateCallback(ship);
		}
	},

	deactivate: function deactivate() {
		botPanel.updateCallback = null;
	},

	setEW: function setEW(ship) {
		botPanel.updateCallback = botPanel.setEW;
		shipWindowManager.addEW(ship, $("#botPanel"));
	},
};;

