    showSurrenderButton: function showSurrenderButton() {
        $(".surrender").on('click', gamedata.onSurrenderClicked).show();
    },

    hideSurrenderButton: function hideSurrenderButton() {
        $(".surrender").off('click', gamedata.onSurrenderClicked).hide();
    },


